// Limita a los N más recientes actualizados para acotar coste.
// Cambia este número si quieres más profundidad.
const MAX = 100;
const tickets = $input.all().map(i => i.json).filter(t => t && t.id);
tickets.sort((a,b) => new Date(b.updated_at) - new Date(a.updated_at));
const limited = tickets.slice(0, MAX);
return limited.map(t => ({ json: t }));

// Pase 1: para cada ticket, mira el último comentario PÚBLICO y compara con
// requester_id. Tickets sin comentario público (típicamente native_messaging)
// se acumulan en pendingMetrics para resolverlos en pase 2 con ticket_metrics.
const tickets = $('Limitar a 100').all().map(i => i.json);
const commentResps = $input.all().map(i => i.json);

const matches = [];
const pendingMetrics = []; // tickets que necesitan resolución vía ticket_metrics
const skippedDebug = [];
let lastByUser = 0, lastByAgent = 0;

const ticketByIdJson = {};
for (const t of tickets) ticketByIdJson[t.id] = t;

for (let i = 0; i < tickets.length; i++) {
  const t = tickets[i];
  const cr = commentResps[i] || {};
  const allComments = Array.isArray(cr.comments) ? cr.comments : [];
  const last = allComments.find(c => c && c.public === true);
  if (!last) {
    pendingMetrics.push(t.id);
    skippedDebug.push({
      ticket_id: t.id,
      subject: t.subject,
      requester_id: t.requester_id,
      url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`,
      total_comments_returned: allComments.length,
      last_5: allComments.slice(0, 5).map(c => ({
        created_at: c.created_at, public: c.public, author_id: c.author_id,
        is_requester: c.author_id === t.requester_id, type: c.type,
        channel: (c.via && c.via.channel) || null,
        body_preview: (c.body || c.html_body || '').toString().replace(/<[^>]+>/g,'').slice(0, 60)
      }))
    });
    continue;
  }
  const userIsLast = (last.author_id === t.requester_id);
  if (userIsLast) lastByUser++; else lastByAgent++;
  if (userIsLast) {
    const ageDays = t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null;
    const sinceLastDays = last.created_at ? Math.floor((Date.now() - new Date(last.created_at).getTime()) / 86400000) : null;
    matches.push({
      ticket_id: t.id, subject: t.subject, status: t.status,
      age_days: ageDays, days_since_user_updated: sinceLastDays,
      last_comment_at: last.created_at, last_author_id: last.author_id,
      requester_id: t.requester_id, assignee_id: t.assignee_id,
      is_public: true, source: 'comment',
      url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
    });
  }
}

// CSV de IDs pendientes para que el siguiente nodo HTTP haga show_many con metric_sets.
// Si no hay pendientes, usamos '0' (devuelve tickets vacíos sin error).
const pendingCsv = pendingMetrics.length ? pendingMetrics.join(',') : '0';

return [{ json: {
  _pre_matches: matches,
  _ticket_by_id: ticketByIdJson,
  _last_by_user_count: lastByUser,
  _last_by_agent_count: lastByAgent,
  _skipped_debug: skippedDebug,
  _pending_metrics_ids: pendingMetrics,
  _tickets_open_total: tickets.length,
  pending_ids_csv: pendingCsv
} }];

// Emite 1 item por ticket pendiente para que el HTTP siguiente haga audits por cada uno.
// Si no hay pendientes emite un dummy (id=0) para no romper la cadena.
const pre = $input.first().json;
const ids = pre._pending_metrics_ids || [];
const tickets = pre._ticket_by_id || {};
const items = ids.map(id => tickets[id]).filter(Boolean);
if (items.length === 0) return [{ json: { id: 0, _dummy: true } }];
return items.map(t => ({ json: t }));

// Pase 2: para los tickets saltados (sin comentario público — típicamente native_messaging),
// usa la Audits API. Cada audit tiene author_id real, incluyendo agentes no-asignados.
// Buscamos el último audit con author_id válido (no system/trigger) y comparamos con requester_id.
const pre = $('Cross Reference').first().json;
const splitItems = $('Split Pending').all().map(i => i.json);
const auditResps = $input.all().map(i => i.json);

const matches = [...(pre._pre_matches || [])];
let auditAdded = 0;
const auditDebug = [];

for (let i = 0; i < splitItems.length; i++) {
  const t = splitItems[i];
  if (!t || !t.id || t.id === 0) continue; // dummy
  const audits = (auditResps[i] && Array.isArray(auditResps[i].audits)) ? auditResps[i].audits : [];
  const lastReal = audits.find(a => a && typeof a.author_id === 'number' && a.author_id > 0);
  const lastIsRequester = lastReal ? (lastReal.author_id === t.requester_id) : null;
  // Debug SIEMPRE: incluye los que no se contaron para entender por qué.
  auditDebug.push({
    ticket_id: t.id,
    requester_id: t.requester_id,
    audits_returned: audits.length,
    all_author_ids: audits.map(a => (a && a.author_id != null) ? a.author_id : null),
    via_channels: audits.map(a => (a && a.via && a.via.channel) || null),
    last_audit_author_id: lastReal ? lastReal.author_id : null,
    last_audit_created_at: lastReal ? lastReal.created_at : null,
    is_requester: lastIsRequester,
    matched: lastIsRequester === true
  });
  if (!lastReal) continue;
  if (lastIsRequester) {
    const ageDays = t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null;
    const lastTime = new Date(lastReal.created_at).getTime();
    const sinceLastDays = Math.floor((Date.now() - lastTime) / 86400000);
    matches.push({
      ticket_id: t.id, subject: t.subject, status: t.status,
      age_days: ageDays, days_since_user_updated: sinceLastDays,
      last_comment_at: lastReal.created_at,
      last_author_id: lastReal.author_id,
      requester_id: t.requester_id, assignee_id: t.assignee_id,
      is_public: null, source: 'audit',
      url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
    });
    auditAdded++;
  }
}

matches.sort((a,b) => (a.days_since_user_updated ?? 999) - (b.days_since_user_updated ?? 999));

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_open_total: pre._tickets_open_total,
  tickets_resolved_via_comments: (pre._pre_matches || []).length + (pre._last_by_agent_count || 0),
  tickets_resolved_via_audits_fallback: (pre._pending_metrics_ids || []).length,
  audits_added_to_matches: auditAdded,
  last_by_user_count:  pre._last_by_user_count,
  last_by_agent_count: pre._last_by_agent_count,
  needs_agent_reply_count: matches.length,
  needs_agent_reply_ids_csv: matches.map(m => m.ticket_id).join(','),
  needs_agent_reply: matches,
  _skipped_debug: pre._skipped_debug,
  _audit_debug: auditDebug
} }];
